PyTypeObject* DoInitWrapperKismetMathLibrary(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperKismetMathLibraryType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperKismetMathLibraryPyMethodDefs;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperKismetMathLibrary(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UKismetMathLibrary::StaticClass(), DoInitWrapperKismetMathLibrary);
}

FUPyWrapperKismetMathLibrary* UPyIsKismetMathLibrary(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperKismetMathLibraryType))
	{
		return (FUPyWrapperKismetMathLibrary*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UKismetMathLibrary*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperKismetMathLibrary* PyKismetMathLibrary = UPyIsKismetMathLibrary(PyObj))
		{
			if (!FUPyWrapperObjectBase::ValidateInternalState(PyKismetMathLibrary))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyKismetMathLibrary->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UKismetMathLibrary'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
